656. function GitView() {
657.   const [repos, setRepos] = useState([]);
658.   const [loading, setLoading] = useState(true);
659.   const [expandedRepoIds, setExpandedRepoIds] = useState(() => new Set());
660. 
661.   const fetchRepos = useCallback(() => {
662.     setLoading(true);
663.     fetch(apiUrl('/api/git/repos'))
664.       .then((r) => {
665.         if (!r.ok) throw new Error(`${r.status}`);
666.         return r.json();
667.       })
668.       .then((data) => {
669.         const list = Array.isArray(data.repos) ? data.repos : [];
670.         setRepos(list);
671.         if (list.length === 1) {
672.           setExpandedRepoIds(new Set([list[0].id]));
673.         } else {
674.           setExpandedRepoIds(new Set());
675.         }
676.       })
677.       .catch(() => setRepos([]))
678.       .finally(() => setLoading(false));
679.   }, []);
680. 
681.   useEffect(() => {
682.     fetchRepos();
683.   }, [fetchRepos]);
684. 
685.   function toggleRepo(repoId) {
686.     setExpandedRepoIds((prev) => {
687.       const next = new Set(prev);
688.       if (next.has(repoId)) next.delete(repoId);
689.       else next.add(repoId);
690.       return next;
691.     });
692.   }
693. 
694.   if (loading) {
695.     return <div className="px-3 py-4 text-sm text-vscode-text-muted">Loading repositories...</div>;
696.   }
697. 
698.   if (!repos.length) {
699.     return <div className="px-3 py-4 text-sm text-vscode-text-muted">No git repositories found in this workspace.</div>;
700.   }
701. 
702.   return (
703.     <div className="flex h-full min-h-0 flex-col overflow-y-auto overscroll-y-contain">
704.       {repos.map((repo) => (
705.         <RepoGitPanel
706.           key={repo.id}
707.           repo={repo}
708.           isExpanded={expandedRepoIds.has(repo.id)}
709.           onToggle={() => toggleRepo(repo.id)}
710.         />
711.       ))}
712.     </div>
713.   );
714. }
