 function GitView() {
   const [repos, setRepos] = useState([]);
   const [loading, setLoading] = useState(true);
   const [expandedRepoIds, setExpandedRepoIds] = useState(() => new Set());

   const fetchRepos = useCallback(() => {
     setLoading(true);
     fetch(apiUrl('/api/git/repos'))
       .then((r) => {
         if (!r.ok) throw new Error(`${r.status}`);
         return r.json();
       })
       .then((data) => {
         const list = Array.isArray(data.repos) ? data.repos : [];
         setRepos(list);
         if (list.length === 1) {
           setExpandedRepoIds(new Set([list[0].id]));
         } else {
           setExpandedRepoIds(new Set());
         }
       })
       .catch(() => setRepos([]))
       .finally(() => setLoading(false));
   }, []);

   useEffect(() => {
     fetchRepos();
   }, [fetchRepos]);

   function toggleRepo(repoId) {
     setExpandedRepoIds((prev) => {
       const next = new Set(prev);
       if (next.has(repoId)) next.delete(repoId);
       else next.add(repoId);
       return next;
     });
   }

   if (loading) {
     return <div className="px-3 py-4 text-sm text-vscode-text-muted">Loading repositories...</div>;
   }

   if (!repos.length) {
     return <div className="px-3 py-4 text-sm text-vscode-text-muted">No git repositories found in this workspace.</div>;
   }

   return (
     <div className="flex h-full min-h-0 flex-col overflow-y-auto overscroll-y-contain">
       {repos.map((repo) => (
         <RepoGitPanel
           key={repo.id}
           repo={repo}
           isExpanded={expandedRepoIds.has(repo.id)}
           onToggle={() => toggleRepo(repo.id)}
         />
       ))}
     </div>
   );
 }

 function SearchView() {
   return (
     <div className="flex h-full min-h-0 flex-col overflow-y-auto overscroll-y-contain">
       <div className="px-4 py-8 text-center">
         <div className="inline-flex items-center justify-center w-16 h-16 mb-4 rounded-full bg-vscode-sidebar-hover">
           <svg className="w-8 h-8 text-vscode-text-muted" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
           </svg>
         </div>
         <h3 className="text-lg font-medium text-vscode-text mb-2">Search</h3>
         <p className="text-sm text-vscode-text-muted max-w-md mx-auto">
           Search functionality coming soon. This will allow you to search for files and text across your workspace.
         </p>
       </div>
     </div>
   );
 }

 const SUB_TABS = [
   { id: 'file-explorer', label: 'Files' },
   { id: 'source-control', label: 'Git' },
   { id: 'search', label: 'Search' },
 ];

 export default function WorkspaceView({ onOpenFile }) {
   const [activeSubTab, setActiveSubTab] = useState(() => {
